using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Persistence;using verii_metivon_api.Modules.Shipping.Application.Services;using verii_metivon_api.Modules.Shipping.Domain.Entities;
namespace verii_metivon_api.Modules.Shipping.Api;[ApiController,Authorize,Route("api/shipments")]public sealed class ShipmentsController(IShipmentService service,MetivonDbContext db):ControllerBase{
[HttpGet]public async Task<IActionResult>List([FromQuery]ShipmentQuery q,CancellationToken ct){var r=await service.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}
[HttpGet("{id:long}")]public async Task<IActionResult>Get(long id,CancellationToken ct){var e=await db.Shipments.AsNoTracking().Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Shipment not found.",404));return Ok(ApiResponse<object>.Ok(new{e.ShipmentNumber,NumberSeriesId=(long?)null,e.SalesOrderId,e.TradeDossierId,e.ShipmentDate,e.CarrierName,e.VehiclePlate,e.DriverName,e.TrackingNumber,Lines=e.Lines.GroupBy(x=>x.SalesOrderLineId).Select(g=>new{SalesOrderLineId=g.Key,Quantity=g.Sum(x=>x.Quantity),InventorySerialIds=g.Where(x=>x.InventorySerialId.HasValue).Select(x=>x.InventorySerialId!.Value)})}));}
[HttpPost]public async Task<IActionResult>Create(CreateShipmentRequest x,CancellationToken ct){var r=await service.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}
[HttpPut("{id:long}")]public async Task<IActionResult>Update(long id,CreateShipmentRequest r,CancellationToken ct){var e=await db.Shipments.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Shipment not found.",404));if(e.Status!=ShipmentStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft shipments can be edited.",409));if(r.Lines.Count==0)return BadRequest(ApiResponse<object>.Error("At least one shipment line is required.",400));var orderLines=await db.SalesOrderLines.AsNoTracking().Where(x=>x.SalesOrderId==r.SalesOrderId).ToDictionaryAsync(x=>x.Id,ct);if(r.Lines.Any(x=>!orderLines.ContainsKey(x.SalesOrderLineId)))return BadRequest(ApiResponse<object>.Error("Shipment lines must belong to the selected sales order.",400));e.ShipmentNumber=string.IsNullOrWhiteSpace(r.ShipmentNumber)?e.ShipmentNumber:r.ShipmentNumber.Trim().ToUpperInvariant();e.SalesOrderId=r.SalesOrderId;e.TradeDossierId=r.TradeDossierId;e.ShipmentDate=r.ShipmentDate;e.CarrierName=r.CarrierName?.Trim();e.VehiclePlate=r.VehiclePlate?.Trim();e.DriverName=r.DriverName?.Trim();e.TrackingNumber=r.TrackingNumber?.Trim();e.WarehouseId=(await db.SalesOrders.AsNoTracking().Where(x=>x.Id==r.SalesOrderId).Select(x=>x.WarehouseId).FirstAsync(ct));db.ShipmentLines.RemoveRange(e.Lines);e.Lines=[];var n=0;foreach(var l in r.Lines){var source=orderLines[l.SalesOrderLineId];var serials=(l.InventorySerialIds??[]).Where(x=>x>0).Distinct().ToArray();if(serials.Length>0&&serials.Length!=l.Quantity)return BadRequest(ApiResponse<object>.Error("Selected serial count must match shipment quantity.",400));if(serials.Length==0)e.Lines.Add(new(){LineNumber=++n,SalesOrderLineId=source.Id,ProductId=source.ProductId,UnitId=source.UnitId,StorageLocationId=source.StorageLocationId,InventoryStatusId=source.InventoryStatusId,InventoryLotId=source.InventoryLotId,InventorySerialId=source.InventorySerialId,Quantity=l.Quantity});else foreach(var serial in serials)e.Lines.Add(new(){LineNumber=++n,SalesOrderLineId=source.Id,ProductId=source.ProductId,UnitId=source.UnitId,StorageLocationId=source.StorageLocationId,InventoryStatusId=source.InventoryStatusId,InventoryLotId=source.InventoryLotId,InventorySerialId=serial,Quantity=1});}await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}
[HttpPost("{id:long}/ship")]public async Task<IActionResult>Ship(long id,CancellationToken ct){var r=await service.ShipAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpDelete("{id:long}")]public async Task<IActionResult>Delete(long id,CancellationToken ct){var e=await db.Shipments.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Shipment not found.",404));if(e.Status!=ShipmentStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft shipments can be deleted.",409));db.Shipments.Remove(e);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}}
